1950   // Control-dependent range information is later used to prove that a narrow
1951   // definition is not negative (see pushNarrowIVUsers). It's difficult to do
1952   // this on demand because when pushNarrowIVUsers needs this information some
1953   // of the dominating conditions might be already widened.
1954   if (UsePostIncrementRanges)
1955     calculatePostIncRanges(OrigPhi);
1956 
1957   // The rewriter provides a value for the desired IV expression. This may
1958   // either find an existing phi or materialize a new one. Either way, we
1959   // expect a well-formed cyclic phi-with-increments. i.e. any operand not part
1960   // of the phi-SCC dominates the loop entry.
1961   Instruction *InsertPt = &*L->getHeader()->getFirstInsertionPt();
1962   Value *ExpandInst = Rewriter.expandCodeFor(AddRec, WideType, InsertPt);
1963   // If the wide phi is not a phi node, for example a cast node, like bitcast,
1964   // inttoptr, ptrtoint, just skip for now.
1965   if (!(WidePhi = dyn_cast<PHINode>(ExpandInst))) {
1966     // if the cast node is an inserted instruction without any user, we should
1967     // remove it to make sure the pass don't touch the function as we can not
1968     // wide the phi.
1969     if (ExpandInst->hasNUses(0) &&
1970         Rewriter.isInsertedInstruction(cast<Instruction>(ExpandInst)))
1971       DeadInsts.emplace_back(ExpandInst);
1972     return nullptr;
1973   }
1974 
1975   // Remembering the WideIV increment generated by SCEVExpander allows
1976   // widenIVUse to reuse it when widening the narrow IV's increment. We don't
1977   // employ a general reuse mechanism because the call above is the only call to
1978   // SCEVExpander. Henceforth, we produce 1-to-1 narrow to wide uses.
1979   if (BasicBlock *LatchBlock = L->getLoopLatch()) {
1980     WideInc =
1981         dyn_cast<Instruction>(WidePhi->getIncomingValueForBlock(LatchBlock));
1982     if (WideInc) {
1983       WideIncExpr = SE->getSCEV(WideInc);
1984       // Propagate the debug location associated with the original loop
1985       // increment to the new (widened) increment.
1986       auto *OrigInc =
1987           cast<Instruction>(OrigPhi->getIncomingValueForBlock(LatchBlock));
1988 
1989       WideInc->setDebugLoc(OrigInc->getDebugLoc());
1990       // We are replacing a narrow IV increment with a wider IV increment. If
1991       // the original (narrow) increment did not wrap, the wider increment one
1992       // should not wrap either. Set the flags to be the union of both wide
1993       // increment and original increment; this ensures we preserve flags SCEV
1994       // could infer for the wider increment. Limit this only to cases where
1995       // both increments directly increment the corresponding PHI nodes and have
1996       // the same opcode. It is not safe to re-use the flags from the original
1997       // increment, if it is more complex and SCEV expansion may have yielded a
1998       // more simplified wider increment.
1999       bool MatchingOps =
2000           match(OrigInc, m_c_BinOp(m_Specific(OrigPhi), m_Value())) &&
2001           match(WideInc, m_c_BinOp(m_Specific(WidePhi), m_Value())) &&
2002           OrigInc->getOpcode() == WideInc->getOpcode();
2003       if (MatchingOps && isa<OverflowingBinaryOperator>(OrigInc) &&
2004           isa<OverflowingBinaryOperator>(WideInc)) {
2005         WideInc->setHasNoUnsignedWrap(WideInc->hasNoUnsignedWrap() ||
2006                                       OrigInc->hasNoUnsignedWrap());
2007         WideInc->setHasNoSignedWrap(WideInc->hasNoSignedWrap() ||
2008                                     OrigInc->hasNoSignedWrap());
2009       }
2010     }
2011   }
2012 
2013   LLVM_DEBUG(dbgs() << "Wide IV: " << *WidePhi << "\n");
2014   ++NumWidened;
2015 
2016   // Traverse the def-use chain using a worklist starting at the original IV.
2017   assert(Widened.empty() && NarrowIVUsers.empty() && "expect initial state" );
2018 
2019   Widened.insert(OrigPhi);
2020   pushNarrowIVUsers(OrigPhi, WidePhi);
2021 
2022   while (!NarrowIVUsers.empty()) {
2023     WidenIV::NarrowIVDefUse DU = NarrowIVUsers.pop_back_val();
2024 
2025     // Process a def-use edge. This may replace the use, so don't hold a
2026     // use_iterator across it.
2027     Instruction *WideUse = widenIVUse(DU, Rewriter);
2028 
2029     // Follow all def-use edges from the previous narrow use.
2030     if (WideUse)
2031       pushNarrowIVUsers(DU.NarrowUse, WideUse);
2032 
2033     // widenIVUse may have removed the def-use edge.
2034     if (DU.NarrowDef->use_empty())
2035       DeadInsts.emplace_back(DU.NarrowDef);
2036   }
2037 
2038   // Attach any debug information to the new PHI.
2039   replaceAllDbgUsesWith(*OrigPhi, *WidePhi, *WidePhi, *DT);
2040 
2041   return WidePhi;
