2122 /// Calculates PostIncRangeInfos map for the given IV
2123 void WidenIV::calculatePostIncRanges(PHINode *OrigPhi) {
2124   SmallPtrSet<Instruction *, 16> Visited;
2125   SmallVector<Instruction *, 6> Worklist;
2126   Worklist.push_back(OrigPhi);
2127   Visited.insert(OrigPhi);
2128 
2129   while (!Worklist.empty()) {
2130     Instruction *NarrowDef = Worklist.pop_back_val();
2131 
2132     for (Use &U : NarrowDef->uses()) {
2133       auto *NarrowUser = cast<Instruction>(U.getUser());
2134 
2135       // Don't go looking outside the current loop.
2136       auto *NarrowUserLoop = (*LI)[NarrowUser->getParent()];
2137       if (!NarrowUserLoop || !L->contains(NarrowUserLoop))
2138         continue;
2139 
2140       if (!Visited.insert(NarrowUser).second)
2141         continue;
2142 
2143       Worklist.push_back(NarrowUser);
2144 
2145       calculatePostIncRange(NarrowDef, NarrowUser);
2146     }
2147   }
2148 }
