2584     unsigned ShiftWidth = TypeSize - 1;
2585     Value *OpL = nullptr, *OpR = nullptr;
2586 
2587     // This is the representation of signum we match:
2588     //
2589     //  signum(x) == (x >> 63) | (-x >>u 63)
