2597     auto LHS = m_AShr(m_Value(OpL), m_SpecificInt(ShiftWidth));
2598     auto RHS = m_LShr(m_Neg(m_Value(OpR)), m_SpecificInt(ShiftWidth));
2599     auto Signum = m_Or(LHS, RHS);
2600 
2601     return Signum.match(V) && OpL == OpR && Val.match(OpL);
2602   }
2603 };
