138 class PossiblyExactOperator : public Operator {
139 public:
140   enum {
141     IsExact = (1 << 0)
142   };
143 
144 private:
145   friend class Instruction;
146   friend class ConstantExpr;
147 
148   void setIsExact(bool B) {
149     SubclassOptionalData = (SubclassOptionalData & ~IsExact) | (B * IsExact);
150   }
